using Microsoft.ML.Data;

namespace TicketClassifier.Models;

/// <summary>
/// Input schema that maps to the training CSV columns.
/// </summary>
public sealed class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

/// <summary>
/// ML.NET prediction output.
/// </summary>
public sealed class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

/// <summary>
/// API request body for ticket classification.
/// </summary>
public sealed class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; } = 3;
}

namespace TicketClassifier.Models;

/// <summary>
/// API response for ticket classification.
/// </summary>
public sealed class PredictionResponse
{
    public required string PredictedCategory { get; set; }
    public required Dictionary<string, float> Confidence { get; set; }
}

namespace TicketClassifier.Models;

/// <summary>
/// API response containing model evaluation metrics.
/// </summary>
public sealed class EvaluationResponse
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public required IReadOnlyList<CategoryMetric> PerCategory { get; set; }
}

public sealed class CategoryMetric
{
    public required string Category { get; set; }
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly EvaluationResponse _metrics;
    private readonly IReadOnlyList<string> _labels;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        IDataView dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        (_model, _metrics, _labels) = TrainAndEvaluate(dataView);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _labels.Count; i++)
        {
            confidence[_labels[i]] = prediction.Score.Length > i ? prediction.Score[i] : 0f;
        }

        return new PredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        };
    }

    public EvaluationResponse GetMetrics() => _metrics;

    private (ITransformer model, EvaluationResponse metrics, IReadOnlyList<string> labels) TrainAndEvaluate(
        IDataView dataView)
    {
        // Combine Subject + Description into a single text feature,
        // then featurize text alongside the numeric Priority column.
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // With a small dataset we train on all data and evaluate on the same set
        // to report non-trivial metrics. In production, use cross-validation.
        var model = pipeline.Fit(dataView);

        IDataView predictions = model.Transform(dataView);
        MulticlassClassificationMetrics eval =
            _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        // Extract ordered label names from the key column
        VBuffer<ReadOnlyMemory<char>> labelBuffer = default;
        predictions.Schema["PredictedLabel"]
            .GetKeyValues(ref labelBuffer);
        var labels = labelBuffer.DenseValues()
            .Select(v => v.ToString())
            .ToList();

        // Build per-category metrics from the confusion matrix
        var perCategory = new List<CategoryMetric>();
        var matrix = eval.ConfusionMatrix;
        for (int i = 0; i < matrix.NumberOfClasses; i++)
        {
            double tp = matrix.GetCountForClassPair(i, i);
            double rowSum = Enumerable.Range(0, matrix.NumberOfClasses)
                .Sum(j => matrix.GetCountForClassPair(i, j));
            double colSum = Enumerable.Range(0, matrix.NumberOfClasses)
                .Sum(j => matrix.GetCountForClassPair(j, i));

            double precision = colSum > 0 ? tp / colSum : 0;
            double recall = rowSum > 0 ? tp / rowSum : 0;
            double f1 = (precision + recall) > 0 ? 2 * precision * recall / (precision + recall) : 0;

            perCategory.Add(new CategoryMetric
            {
                Category = i < labels.Count ? labels[i] : $"Class{i}",
                Precision = precision,
                Recall = recall,
                F1Score = f1
            });
        }

        var metrics = new EvaluationResponse
        {
            MacroAccuracy = eval.MacroAccuracy,
            MicroAccuracy = eval.MicroAccuracy,
            LogLoss = eval.LogLoss,
            LogLossReduction = eval.LogLossReduction,
            PerCategory = perCategory
        };

        return (model, metrics, labels);
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketsController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    /// <summary>
    /// Predict the category of a support ticket.
    /// </summary>
    [HttpPost("classify")]
    public ActionResult<PredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) || string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject and Description are required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        return Ok(_classifier.Predict(request));
    }

    /// <summary>
    /// Return evaluation metrics for the trained model.
    /// </summary>
    [HttpGet("metrics")]
    public ActionResult<EvaluationResponse> Metrics()
    {
        return Ok(_classifier.GetMetrics());
    }
}

